const styles = {
  modal: {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center'
  },
  containerList: {
    background: 'white',
    maxHeight: '90%',
    width: '700px',
    overflowX: 'hidden'
  },

  title: {
    color: '#121012',
    padding: '1em',
    height: '25px'
  },

  text: {
    color: '#121012',
    padding: '1em'
  }
}

export default styles
